import{_ as t,o as s,c as o,a2 as d}from"./chunks/framework.il0noOp3.js";const u=JSON.parse('{"title":"Assessment Prerequisites","description":"Software, PowerShell module, and .NET SDK prerequisites specific to the AzureScout CAF/WAF assessment platform (Invoke-ScoutAssessment).","frontmatter":{"description":"Software, PowerShell module, and .NET SDK prerequisites specific to the AzureScout CAF/WAF assessment platform (Invoke-ScoutAssessment)."},"headers":[],"relativePath":"assessment-prerequisites.md","filePath":"assessment-prerequisites.md"}'),r={name:"assessment-prerequisites.md"};function a(i,e,n,c,l,h){return s(),o("div",null,[...e[0]||(e[0]=[d(`<h1 id="assessment-prerequisites" tabindex="-1">Assessment Prerequisites <a class="header-anchor" href="#assessment-prerequisites" aria-label="Permalink to &quot;Assessment Prerequisites&quot;">​</a></h1><p>These prerequisites are <strong>specific to the CAF/WAF assessment platform</strong> (<code>Invoke-ScoutAssessment</code>, <code>Test-ScoutPermission</code>). They are additional to — not a replacement for — the v1 inventory prerequisites in <a href="./prerequisites.html">Prerequisites &amp; Required Modules</a>.</p><div class="tip custom-block"><p class="custom-block-title">PowerShell 7 is a hard requirement</p><p>Every assessment-platform script starts with <code>#Requires -Version 7.0</code>. Unlike the v1 inventory cmdlet (<code>Invoke-AzureScout</code>), which still runs on Windows PowerShell 5.1, <strong><code>Invoke-ScoutAssessment</code> will not load under PowerShell 5.1</strong> — the <code>#Requires</code> statement blocks it outright.</p></div><h2 id="system-requirements" tabindex="-1">System requirements <a class="header-anchor" href="#system-requirements" aria-label="Permalink to &quot;System requirements&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requirement</th><th>Details</th></tr></thead><tbody><tr><td>PowerShell</td><td>7.0.3+ (source: <a href="./design/master-plan.html#10-dependencies-from-spec-10"><code>docs/design/master-plan.md</code> §10</a>)</td></tr><tr><td>Operating System</td><td>Windows, Linux, or macOS — the platform is pure PowerShell/.NET</td></tr><tr><td>.NET SDK</td><td>Required only for the PowerPoint (<code>Pptx</code>) report tier — see <a href="#powerpoint-tier-net-sdk-not-python">below</a></td></tr><tr><td><code>git</code></td><td>Required only if you opt an assessment into the legacy <code>AzGovViz</code> ingestor instead of the native <code>Governance</code> default (see <a href="./assessment-permissions.html">Auth &amp; permissions</a>) — used to shallow-clone the Azure Governance Visualizer tool at first use. Not needed by any assessment out of the box.</td></tr></tbody></table><h2 id="required-powershell-modules" tabindex="-1">Required PowerShell modules <a class="header-anchor" href="#required-powershell-modules" aria-label="Permalink to &quot;Required PowerShell modules&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Not all of these are auto-installed</p><p>AzureScout&#39;s module bootstrap (<code>AzureScout.psm1</code>) auto-installs a fixed list of modules on import: <code>ImportExcel</code>, <code>Az.Accounts</code>, <code>Az.ResourceGraph</code>, <code>Az.Storage</code>, <code>Az.Compute</code>, <code>Az.Resources</code>. That list was written for the v1 inventory cmdlet and <strong>does not include <code>powershell-yaml</code> or <code>Az.Advisor</code></strong>, both of which the assessment platform needs. If either is missing, <code>Invoke-ScoutAssessment</code> throws when it reaches the step that needs it, rather than auto-installing it for you. Install them manually before your first assessment run (below).</p></div><table tabindex="0"><thead><tr><th>Module</th><th>Purpose</th><th>Required for</th><th>Auto-installed by <code>AzureScout.psm1</code>?</th></tr></thead><tbody><tr><td><code>Az.Accounts</code></td><td>Authentication / token acquisition</td><td>All</td><td>Yes</td></tr><tr><td><code>Az.ResourceGraph</code></td><td>The Collect layer&#39;s Resource Graph queries</td><td>All</td><td>Yes</td></tr><tr><td><code>Az.Resources</code></td><td>Role assignment reads (permission pre-flight)</td><td>All</td><td>Yes</td></tr><tr><td><code>powershell-yaml</code></td><td>Parses the <code>caf.*</code>/<code>waf.*</code> rule YAML files (<code>Get-RuleSet</code>)</td><td>All scoring (any assessment with <code>Rules</code>)</td><td><strong>No — install manually</strong></td></tr><tr><td><code>Az.Advisor</code></td><td><code>Get-AzAdvisorRecommendation</code>, used by the <code>AdvisorScores</code> ingest</td><td>Assessments whose <code>Ingest</code> includes <code>AdvisorScores</code> (<code>LandingZone</code>, <code>Management</code>, <code>Security</code>, <code>Compute</code>, <code>Cost</code>)</td><td><strong>No — install manually</strong></td></tr><tr><td><code>ImportExcel</code></td><td>Excel evidence-tier report (<code>Export-Excel</code>)</td><td><code>-OutputFormat Excel</code></td><td>Yes</td></tr><tr><td><code>AzAPICall</code></td><td>Dependency of the third-party Azure Governance Visualizer</td><td>Assessments whose <code>Ingest</code> includes <code>AzGovViz</code></td><td>No — <code>Import-AzGovViz.ps1</code> installs it itself at first use (<code>Install-Module AzAPICall -Scope CurrentUser -Force</code>) if not already present</td></tr></tbody></table><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Manual install — covers the gap in AzureScout.psm1&#39;s auto-bootstrap</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Install-Module</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Name powershell</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">yaml </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Scope CurrentUser </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Force</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Install-Module</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Name Az.Advisor       </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Scope CurrentUser </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Force</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><div class="info custom-block"><p class="custom-block-title"><code>Az.Security</code> is documented, not yet wired up</p><p><code>docs/design/master-plan.md</code> §10 and <code>src/README.md</code> list <code>Az.Security</code> as a dependency, but no current assessment code calls an <code>Az.Security</code> cmdlet — <code>Security</code>-category rules read <code>collect.security.defenderPlans</code>, which the Collect layer (<code>Invoke-Collect.ps1</code>) currently always returns empty (<code>@()</code>). Installing it does no harm, but it is not load-bearing for any assessment today.</p></div><h2 id="powerpoint-tier-—-net-sdk-not-python" tabindex="-1">PowerPoint tier — .NET SDK, not Python <a class="header-anchor" href="#powerpoint-tier-—-net-sdk-not-python" aria-label="Permalink to &quot;PowerPoint tier — .NET SDK, not Python&quot;">​</a></h2><p>The <code>Pptx</code> report tier (<code>-OutputFormat Pptx</code>) renders the executive deck with the <strong>OpenXML SDK</strong> (<code>DocumentFormat.OpenXml</code>), not <code>python-pptx</code> and not PowerPoint COM automation — see the accepted decision record, <a href="./design/decisions/pptx-renderer.html">PPTX executive-deck renderer</a>.</p><div class="tip custom-block"><p class="custom-block-title">No Python required</p><p>Earlier design drafts specced a <code>python3</code> + <code>python-pptx</code> shell-out for the PPTX tier. That was superseded — <code>src/report/renderers/Export-Pptx.ps1</code> is pure PowerShell/.NET today. <strong>You do not need Python installed anywhere in the pipeline for any output format.</strong></p></div><p>What <code>Export-Pptx.ps1</code> actually needs, and what happens the first time you run it:</p><ol><li>On first use, it checks for a cached copy of <code>DocumentFormat.OpenXml</code> 3.0.2 (and its transitive dependencies) under <code>output/.tools/openxml/3.0.2/</code>.</li><li>If not cached, it requires the <strong><code>dotnet</code> CLI on <code>PATH</code></strong> — it shells out to <code>dotnet build</code> against a throwaway class-library project that references the NuGet package, which resolves and downloads the assembly graph via NuGet/MSBuild, then caches the three resulting DLLs.</li><li>Every later run (same machine) loads the cached DLLs via <code>Add-Type -Path</code> — no network access, no <code>dotnet</code> needed once the cache is warm.</li><li>If <code>dotnet</code> is not on <code>PATH</code> and nothing is cached, <code>Export-Pptx</code> throws a clear error rather than silently skipping the deck.</li></ol><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Verify the .NET SDK is available before your first -OutputFormat Pptx run</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">dotnet </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">version</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><div class="warning custom-block"><p class="custom-block-title"><code>src/README.md</code> is stale</p><p><code>src/README.md</code>&#39;s Dependencies table still lists <code>python3 + python-pptx</code> for the PPTX tier. That reflects an earlier prototype (<code>src/report/renderers/Export-Pptx.ps1</code> pre-AB#5044) and does not match the accepted, implemented renderer described above and in <a href="./design/decisions/pptx-renderer.html">the decision record</a>. Trust this page and the decision record, not <code>src/README.md</code>, for the PPTX tier.</p></div><h2 id="what-the-estate-v1-inventory-does-not-need" tabindex="-1">What the Estate / v1 inventory does NOT need <a class="header-anchor" href="#what-the-estate-v1-inventory-does-not-need" aria-label="Permalink to &quot;What the Estate / v1 inventory does NOT need&quot;">​</a></h2><p>The <code>Estate</code> assessment (<code>-Assessment Estate</code>) is inventory-only — it has no <code>Rules</code>, so it never calls <code>Get-RuleSet</code> and therefore never needs <code>powershell-yaml</code>. It still runs under PowerShell 7 through the same <code>Invoke-ScoutAssessment</code> entry point, so the PS7 requirement above still applies even though it doesn&#39;t score anything.</p><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><ul><li><a href="./assessment-permissions.html">Auth &amp; permissions per scan type</a></li><li><a href="./assessment.html">Assessment guide — run modes and examples</a></li><li><a href="./design/assessment-registry.html">Assessment Registry — all 22 assessments</a></li></ul>`,21)])])}const m=t(r,[["render",a]]);export{u as __pageData,m as default};
